// 실내 맵 ID — 맵 외곽 영역을 풀밭 대신 검정으로 렌더링
inline bool isIndoorMap(int id) {
    return id == MAP_OAK_LAB || id == MAP_PLAYER_HOUSE ||
           id == MAP_PLAYER_HOUSE2 || id == MAP_PEWTER_GYM ||
           id == MAP_RIVAL_HOUSE;
}

