inline constexpr int NUM_MAPS = 11;

inline MapDef* getMap(int id) {
    if (id >= 0 && id < NUM_MAPS) return ALL_MAPS[id];
    return nullptr;
}

// walkable: 길/잔디/floor만. 가구/벽/워프 char(t,v,w,x,y,z,A,B,C,j,#)는 unwalkable
// → 워프 char는 tryMove의 !walkable 분기에서 워프 트리거.
//   '#' = TILE_WALL (벽), 맵 경계 밖에서도 '#' 반환됨 → unwalkable이어야 경계 차단.
inline bool tileWalkable(char t) {
    return t == ' ' || t == '!' || t == '$' || t == '%' || t == '(' || t == '+' || t == '0' || t == '1' || t == '2' || t == '3' || t == '4' || t == '8' || t == ';' || t == '@' || t == 'H' || t == 'I' || t == 'J' || t == 'K' || t == 'S' || t == 'Z' || t == '^' || t == 'i' || t == 'u';
}
inline bool tileIsEncounter(char t) {
    return t == '2' || t == ';';
}
inline char getTile(const MapDef* m, int x, int y) {
    if (!m || x < 0 || x >= m->mapW || y < 0 || y >= m->mapH) return '#';
    if (!m->tiles[y]) return '#';
    int len = 0; while (m->tiles[y][len]) len++;
    if (x >= len) return ' ';
    return m->tiles[y][x];
}

inline bool tileIsDoor(char t) {
    return t == '!' || t == '#' || t == '(' || t == '1' || t == '@' || t == 'A' || t == 'B' || t == 'H' || t == 'I' || t == 'J' || t == 'K' || t == '^' || t == 'w';
}
